STATIC
VOID

InitSlide ()
/*++ 

Routine Description:
Initialize String Info Log data structures

Arguments: (VOID)

Returns: (VOID)

--*/
{
    NODE i;

    for (i = WNDSIZ; i <= WNDSIZ + UINT8_MAX; i++) {
    mLevel[i] = 1;
    mPosition[i] = NIL; /* sentinel */
    }
    for (i = WNDSIZ; i < WNDSIZ * 2; i++) {
    mParent[i] = NIL;
    }

mAvail = 1;
    for (i = 1; i < WND SIZ - 1; i++) {
    mNext[i] = (NODE)(i + 1);
    }

    mNext[WDNSIZ - 1] = NIL;
    for (i = WND SIZ * 2; i <= MAX_HASH_VAL; i++) {
    mNext[i] = NIL;
    }
}

STATIC
NODE
Child (
    IN NODE q,
    IN UINT8 c
)
/*++
Routine Description:
Find child node given the parent node and the edge character
Arguments:
q - the parent node
c - the edge character
Returns:
The child node (NIL if not found)
--*/
{
    NODE r;

    r = mNext[HASH(q, c)];
    mParent[NIL] = q; /* sentinel */
    while (mParent[r] != q) {
    r = mNext[r];
    }

    return r;
}

STATIC
VOID
MakeChild (
    IN NODE q,
    IN UINT8 c,
    IN NODE r
)

/*++   
Routine Description: Create a new child for a given parent node.   
Arguments: q - the parent node c - the edge character r - the child node   
Returns: (VOID) --*/ { NODE h, t; h = (NODE)HASH(q, c); t = mNext[h]; mNext[h] = r; mNext[r] = t; mPrev[t] = r; mPrev[r] = h; mParent[r] = q; mChildCount[q]++; }   
STATIC VOID Split ( NODE Old ) /*++   
Routine Description: Split a node.   
Arguments: Old - the node to split   
Returns: (VOID) --*/ { NODE New, t; New = mAvail; mAvail = mNext[New]; mChildCount[New] = 0;

t = mPrev[Old];
mPrev[New] = t;
mNext[t] = New;
t = mNext[Old];
mNext[New] = t;
mPrev[t] = New;
mParent[New] = mParent[Old];
mLevel[New] = (UINT8)mMatchLen;
mPosition[New] = mPos;
MakeChild(New, mText[mMatchPos + mMatchLen], Old);
MakeChild(New, mText[mPos + mMatchLen], mPos);
}

STATIC
VOID
InsertNode ()
/*++

Routine Description:
Insert string info for current position into the String Info Log
Arguments: (VOID)
Returns: (VOID)
--*/
{
    NODE q, r, j, t;
    UINT8 c, *t1, *t2;

    if (mMatchLen >= 4) {
    //
    // We have just got a long match, the target tree
    // can be located by MatchPos + 1. Traverse the tree
    // from bottom up to get to a proper starting point.
    // The usage of PERC_FLAG ensures proper node deletion
    // in DeleteNode() later.
    //
    mMatchLen--;
    r = (INT16)((mMatchPos + 1) \ | WNDSIZ);
    while ((q = mParent[r]) == NIL) {
    r = mNext[r];
    }
    while (mLevel[q] >= mMatchLen) {
    r = q; q = mParent[q];
    }
    t = q;
    while (mPosition[t] < 0) {
    mPosition[t] = mPos;

t = mParent[t];
}
if (t < WNDSIZ) {
    mPosition[t] = (NODE)(mPos \ | PERC_FLAG);
}
} else {

    //
    // Locate the target tree
    //
    q = (INT16)(mText[mPos] + WNDSIZ);
    c = mText[mPos + 1];
    if ((r = Child(q, c)) == NIL) {
    MakeChild(q, c, mPos);
    mMatchLen = 1;
    return;
    }
    mMatchLen = 2;
}

// Traverse down the tree to find a match.
// Update Position value along the route.
// Node split or creation is involved.
// 
for ( ; ; ) {
    if (r >= WNDSIZ) {
    j = MAXMATCH;
    mMatchPos = r;
    } else {
    j = mLevel[r];
    mMatchPos = (NODE)(mPosition[r] & ~PERC_FLAG);
    }
    if (mMatchPos >= mPos) {
    mMatchPos -= WNDSIZ;
    }
    t1 = &mText[mPos + mMatchLen];
    t2 = &mText[mMatchPos + mMatchLen];
    while (mMatchLen < j) {
    if (*t1 != *t2) {
    Split(r);
    return;
    }
    mMatchLen++;
    t1++;
    t2++;
    }
    if (mMatchLen >= MAXMATCH) {
    break;
    }

mPosition[r] = mPos;
q = r;
if ((r = Child(q, *t1)) == NIL) {
    MakeChild(q, *t1, mPos);
    return;
}
    mMatchLen++;
}
t = mPrev[r];
mPrev[mPos] = t;
mNext[t] = mPos;
t = mNext[r];
mNext[mPos] = t;
mPrev[t] = mPos;
mParent[mPos] = q;
mParent[r] = NIL;

//
// Special usage of 'next'
//
mNext[r] = mPos;
}

STATIC
VOID
DeleteNode ()
/*++

Routine Description:
Delete outdated string info. (The Usage of PERC_FLAG ensures a clean deletion)

Arguments: (VOID)

Returns: (VOID)

--*/
{
    NODE q, r, s, t, u;

    if (mParent[mPos] == NIL) {
    return;
    }

    r = mPrev[mPos];
    s = mNext[mPos];
    mNext[r] = s;
    mPrev[s] = r;
    r = mParent[mPos];
    mParent[mPos] = NIL;

if (r >= WNSIZ || --mChildCount[r] > 1) {
    return;
}
t = (NODE)(mPosition[r] & ~PERC_FLAG);
if (t >= mPos) {
    t -= WNSIZ;
}
s = t;
q = mParent[r];
while ((u = mPosition[q]) & PERC_FLAG) {
    u &= ~PERC_FLAG;
    if (u >= mPos) {
    u -= WNSIZ;
    }
    if (u > s) {
    s = u;
    }
    mPosition[q] = (INT16)(s \ | WNSIZ);
    q = mParent[q];
}
if (q < WNSIZ) {
    if (u >= mPos) {
    u -= WNSIZ;
    }
    if (u > s) {
    s = u;
    }
    mPosition[q] = (INT16)(s \ | WNSIZ \ | PERC_FLAG);
    }
    s = Child(r, mText[t + mLevel[r]]);
    t = mPrev[s];
    u = mNext[s];
    mNext[t] = u;
    mPrev[u] = t;
    t = mPrev[r];
    mNext[t] = s;
    mPrev[s] = t;
    t = mNext[r];
    mPrev[t] = s;
    mNext[s] = t;
    mParent[s] = mParent[r];
    mParent[r] = NIL;
    mNext[r] = mAvail;
    mAvail = r;
}

STATIC
VOID
GetNextMatch ()
/*++ 

Routine Description:

Advance the current position (read in new data if needed).
Delete outdated string info. Find a match string for current position.

Arguments: (VOID)

Returns: (VOID)

--*/
{
    INT32 n;

    mRemainder--;
    if (++mPos == WND SIZ * 2) {
    memmove(&mText[0], &mText[WDNSIZ], WND SIZ + MAXMATCH);
    n = FreadCrc(&mText[WDNSIZ + MAXMATCH], WND SIZ);
    mRemainder += n;
    mPos = WND SIZ;
    }
    DeleteNode();
    InsertNode();
}

STATIC
EFI_STATUS
Encode ()
/*++>

Routine Description:
The main controlling routine for compression process.

Arguments: (VOID)

Returns:
EFI_SUCCESS - The compression is successful
EFI_OUT_OF_RESOURCES - Not enough memory for compression process

--*/
{
    EFI_STATUS Status;
    INT32 LastMatchLen;
    NODE LastMatchPos;

Status = AllocateMemory();
if (EFI_ERROR(Status)) {
    FreeMemory();
    return Status;
}

InitSlide();

HufEncodeStart();

mRemainder = FreadCrc(&mText[WNDSIZ], WNDSIZ + MAXMATCH);

mMatchLen = 0;
mPos = WNDSIZ;
InsertNode();
if (mMatchLen > mRemainder) {
    mMatchLen = mRemainder;
}
while (mRemainder > 0) {
    LastMatchLen = mMatchLen;
    LastMatchPos = mMatchPos;
    GetNextMatch();
    if (mMatchLen > mRemainder) {
    mMatchLen = mRemainder;
    }

    if (mMatchLen > LastMatchLen \\|\\ LastMatchLen < THRESHOLD) {

    //
    // Not enough benefits are gained by outputting a pointer,
    // so just output the original character
    //
    Output(mText[mPos - 1], 0);
} else {

    //
    // Outputting a pointer is beneficial enough, do it.
    //
    Output(LastMatchLen + (UINT8_MAX + 1 - THRESHOLD),
    (mPos - LastMatchPos - 2) & (WNDSIZ - 1));
    while (--LastMatchLen > 0) {
    GetNextMatch();
    }
    if (mMatchLen > mRemainder) {
    mMatchLen = mRemainder;
    }
    }
}

HufEncodeEnd();
FreeMemory();
return EFI_SUCCESS;
}

STATIC
VOID
CountTFreq ()

)
/*++

Routine Description:
Outputs the code length array for the Extra Set or the Position Set.

Arguments:
n - the number of symbols
nbit - the number of bits needed to represent 'n'
Special - the special symbol that needs to be take care of

Returns: (VOID)

--*/
{
    INT32 i, k;

    while (n > 0 && mPTLen[n - 1] == 0) {
    n--;
    }
    PutBits(nbit, n);
    i = 0;
    while (i < n) {
    k = mPTLen[i++];
    if (k <= 6) {
    PutBits(3, k);
    } else {
    PutBits(k - 3, (1U << (k - 3)) - 2);
    }
    if (i == Special) {
    while (i < 6 && mPTLen[i] == 0) {
    i++;
    }
    PutBits(2, (i - 3) & 3);
    }
    }
}

STATIC
VOID
WriteCLen ()
/*++

Routine Description:
Outputs the code length array for Char&Length Set

Arguments: (VOID)

Returns: (VOID)

--*/
{
    INT32 i, k, n, Count;

    n = NC;
    while (n > 0 && mCLen[n - 1] == 0) {
    n--;
    }
    PutBits(CBIT, n);
    i = 0;
    while (i < n) {
    k = mCLen[i++];
    if (k == 0) {
    Count = 1;
    while (i < n && mCLen[i] == 0) {
    i++;
    Count++;
    }
    if (Count <= 2) {
    for (k = 0; k < Count; k++) {
    PutBits(mPTLen[0], mPTCode[0]);
    }
    } else if (Count <= 18) {
    PutBits(mPTLen[1], mPTCode[1]);
    PutBits(4, Count - 3);
    } else if (Count == 19) {
    PutBits(mPTLen[0], mPTCode[0]);
    PutBits(mPTLen[1], mPTCode[1]);
    PutBits(4, 15);
    } else {
    PutBits(mPTLen[2], mPTCode[2]);
    PutBits(CBIT, Count - 20);
    }
    } else {
    PutBits(mPTLen[k + 2], mPTCode[k + 2]);
    }
    }
}

STATIC
VOID
EncodeC (
    IN INT32 c
)
{
    PutBits(mCLen[c], mCCode[c]);
}

STATIC
VOID
EncodeP (

IN UINT32 p
)
{
    UINT32 c, q;

    c = 0;
    q = p;
    while (q) {
    q >>= 1;
    c++;
    }
    PutBits(mPTLen[c], mPTCode[c]);
    if (c > 1) {
    PutBits(c - 1, p & (0xFFFFU >> (17 - c)));
    }
}

STATIC
VOID
SendBlock ()
/*++

Routine Description:
Huffman code the block and output it.

Argument: (VOID)

Returns: (VOID)

--*/
{
    UINT32 i, k, Flags, Root, Pos, Size;
    Flags = 0;

    Root = MakeTree(NC, mCFreq, mCLen, mCCode);
    Size = mCFreq[Root];
    PutBits(16, Size);
    if (Root >= NC) {
    CountTFreq();
    Root = MakeTree(NT, mTFreq, mPTLen, mPTCode);
    if (Root >= NT) {
    WritePTLen(NT, TBIT, 3);
    } else {
    PutBits(TBIT, 0);
    PutBits(TBIT, Root);
    }
    WriteCLen();
    } else {
    PutBits(TBIT, 0);
    PutBits(TBIT, 0);

PutBits(CBIT, 0);
PutBits(CBIT, Root);
}
Root = MakeTree(NP, mPFreq, mPTLen, mPTCode);
if (Root >= NP) {
    WritePTLen(NP, PBIT, -1);
} else {
    PutBits(PBIT, 0);
    PutBits(PBIT, Root);
}
Pos = 0;
for (i = 0; i < Size; i++) {
    if (i % UINT8_BIT == 0) {
    Flags = mBuf[Pos++];
    } else {
    Flags <<= 1;
    }
    if (Flags & (1U << (UINT8_BIT - 1))) {
    EncodeC(mBuf[Pos++] + (1U << UINT8_BIT));
    k = mBuf[Pos++] << UINT8_BIT;
    k += mBuf[Pos++];
    EncodeP(k);
    } else {
    EncodeC(mBuf[Pos++]);
    }
    }
    for (i = 0; i < NC; i++) {
    mCFreq[i] = 0;
    }
    for (i = 0; i < NP; i++) {
    mPFreq[i] = 0;
    }
}

STATIC
VOID
Output (
    IN UINT32 c,
    IN UINT32 p
)
/*++
Routine Description:
Outputs an Original Character or a Pointer

Arguments:
c - The original character or the 'String Length' element of a Pointer
p - The 'Position' field of a Pointer

Returns: (VOID)

--*/
{
    STATIC UINT32 CPos;

    if ((mOutputMask >>= 1) == 0) {
    mOutputMask = 1U << (UINT8_BIT - 1);
    if (mOutputPos >= mBufSiz - 3 * UINT8_BIT) {
    SendBlock();
    mOutputPos = 0;
    }
    CPos = mOutputPos++;
    mBuf[CPos] = 0;
    }
    mBuf[mOutputPos++] = (UINT8) c;
    mCFreq[c]++;
    if (c >= (1U << UINT8_BIT)) {
    mBuf[CPos] \ |= mOutputMask;
    mBuf[mOutputPos++] = (UINT8)(p >> UINT8_BIT);
    mBuf[mOutputPos++] = (UINT8) p;
    c = 0;
    while (p) {
    p >>= 1;
    c++;
    }
    mPFreq[c]++;
    }
}

STATIC
VOID
HufEncodeStart ()
{
    INT32 i;

    for (i = 0; i < NC; i++) {
    mCFreq[i] = 0;
    }
    for (i = 0; i < NP; i++) {
    mPFreq[i] = 0;
    }
    mOutputPos = mOutputMask = 0;
    InitPutBits();
    return;
}

STATIC
VOID
HufEncodeEnd ()
{
    SendBlock();

// Flush remaining bits
// PutBits(UINT8_BIT - 1, 0);

return;
}

STATIC
VOID
MakeCrcTable ()
{
    UINT32 i, j, r;

    for (i = 0; i <= UINT8_MAX; i++) {
    r = i;
    for (j = 0; j < UINT8_BIT; j++) {
    if (r & 1) {
    r = (r >> 1) ^ CRCPOLY;
    } else {
    r >>= 1;
    }
    }
    mCrcTable[i] = (UINT16)r;
    }
}

STATIC
VOID
PutBits (
    IN INT32 n,
    IN UINT32 x
)
/*++ 

Routine Description:
Outputs rightmost n bits of x

Arguments:
n - the rightmost n bits of the data is used
x - the data

Returns: (VOID)

--*/
{
    UINT8 Temp;

if (n < mBitCount) {
    mSubBitBuf \ |= x << (mBitCount -= n);

} else {
Temp = (UINT8)(mSubBitBuf \ | (x >> (n -= mBitCount)));
if (mDst < mDstUpperLimit) {
    *mDst++ = Temp;
}
mCompSize++;
if (n < UINT8_BIT) {
    mSubBitBuf = x << (mBitCount = UINT8_BIT - n);
} else {
Temp = (UINT8)(x >> (n - UINT8_BIT));
if (mDst < mDstUpperLimit) {
    *mDst++ = Temp;
}
mCompSize++;
mSubBitBuf = x << (mBitCount = 2 * UINT8_BIT - n);
}
}

STATIC
INT32
FreadCrc (
OUT UINT8 *p,
IN INT32 n
)
/*++
Routine Description:
Read in source data
Arguments:
p - the buffer to hold the data
n - number of bytes to read
Returns:
number of bytes actually read
--*/
{
INT32 i;

for (i = 0; mSrc < mSrcUpperLimit && i < n; i++) {
    *p++ = *mSrc++;
}
n = i;

p -= n;
mOrigSize += n;
while (--i >= 0) {
    UPDATE_CRC(*p++);
}
return n;
}

STATIC
VOID
InitPutBits ()
{
    mBitCount = UINT8_BIT;
    mSubBitBuf = 0;
}

STATIC
VOID
CountLen (
    IN INT32 i
)
/*++

Routine Description:
Count the number of each code length for a Huffman tree.

Arguments:
i - the top node

Returns: (VOID)

--*/
{
    STATIC INT32 Depth = 0;

    if (i < mN) {
    mLenCnt[(Depth < 16) ? Depth : 16]++;
    } else {
    Depth++;
    CountLen(mLeft [i]);
    CountLen(mRight[i]);
    Depth--;
    }
}

STATIC
VOID
MakeLen (
    IN INT32 Root

)
/*++

Routine Description:
    Create code length array for a Huffman tree
Arguments:
    Root - the root of the tree
--*/
{
    INT32 i, k;
    UINT32 Cum;

    for (i = 0; i <= 16; i++) {
    mLenCnt[i] = 0;
    }
    CountLen(Root);

    //
    // Adjust the length count array so that
    // no code will be generated longer than the designated length
    //
    Cum = 0;
    for (i = 16; i > 0; i--) {
    Cum += mLenCnt[i] << (16 - i);
    }
    while (Cum != (1U << 16)) {
    mLenCnt[16]--;
    for (i = 15; i > 0; i--) {
