    Start[1] = 0;
    for (i = 1; i <= 16; i++) {
    Start[i + 1] = (UINT16)((Start[i] + mLenCnt[i]) << 1);
}

for (i = 0; i < n; i++) {
    Code[i] = Start[Len[i]]++;
}
